import android.content.Context
import android.content.Intent
import android.os.Bundle
import android.widget.Button
import android.widget.EditText
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat
import java.util.concurrent.Executor

class LoginActivity : AppCompatActivity() {
    
    private lateinit var biometricPrompt: BiometricPrompt
    private lateinit var promptInfo: BiometricPrompt.PromptInfo
    private lateinit var executor: Executor
    
    private lateinit var etPassword: EditText
    private lateinit var btnLogin: Button
    private lateinit var btnBiometric: Button
    
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        
        if (isUserAuthenticated()) {
            navigateToMainActivity()
            return
        }
        
        setContentView(R.layout.activity_login)
        
        etPassword = findViewById(R.id.etPassword)
        btnLogin = findViewById(R.id.btnLogin)
        btnBiometric = findViewById(R.id.btnBiometric)
        
        executor = ContextCompat.getMainExecutor(this)
        
        setupBiometricPrompt()
        checkBiometricAvailability()
        
        btnLogin.setOnClickListener {
            handlePasswordLogin()
        }
        
        btnBiometric.setOnClickListener {
            showBiometricPrompt()
        }
        
        if (canUseBiometric()) {
            showBiometricPrompt()
        }
    }
    
    private fun setupBiometricPrompt() {
        biometricPrompt = BiometricPrompt(this, executor, 
            object : BiometricPrompt.AuthenticationCallback() {
                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)
                    Toast.makeText(this@LoginActivity, 
                        "Authentication error: $errString", Toast.LENGTH_SHORT).show()
                }
                
                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)
                    saveAuthenticationStatus(true)
                    Toast.makeText(this@LoginActivity, 
                        "Authentication succeeded!", Toast.LENGTH_SHORT).show()
                    navigateToMainActivity()
                }
                
                override fun onAuthenticationFailed() {
                    super.onAuthenticationFailed()
                    Toast.makeText(this@LoginActivity, 
                        "Authentication failed. Please try again.", Toast.LENGTH_SHORT).show()
                }
            })
        
        promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Biometric Login")
            .setSubtitle("Log in using your fingerprint or face")
            .setDescription("Place your finger on the sensor or look at the camera")
            .setNegativeButtonText("Use Password")
            .setAllowedAuthenticators(
                BiometricManager.Authenticators.BIOMETRIC_STRONG or
                BiometricManager.Authenticators.BIOMETRIC_WEAK
            )
            .build()
    }
    
    private fun checkBiometricAvailability() {
        val biometricManager = BiometricManager.from(this)
        when (biometricManager.canAuthenticate(
            BiometricManager.Authenticators.BIOMETRIC_STRONG or
            BiometricManager.Authenticators.BIOMETRIC_WEAK
        )) {
            BiometricManager.BIOMETRIC_SUCCESS -> {
                btnBiometric.isEnabled = true
            }
            BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE -> {
                btnBiometric.isEnabled = false
                Toast.makeText(this, "No biometric hardware available", Toast.LENGTH_SHORT).show()
            }
            BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE -> {
                btnBiometric.isEnabled = false
                Toast.makeText(this, "Biometric hardware unavailable", Toast.LENGTH_SHORT).show()
            }
            BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED -> {
                btnBiometric.isEnabled = false
                Toast.makeText(this, "No biometric credentials enrolled", Toast.LENGTH_SHORT).show()
            }
            else -> {
                btnBiometric.isEnabled = false
            }
        }
    }
    
    private fun canUseBiometric(): Boolean {
        val biometricManager = BiometricManager.from(this)
        return biometricManager.canAuthenticate(
            BiometricManager.Authenticators.BIOMETRIC_STRONG or
            BiometricManager.Authenticators.BIOMETRIC_WEAK
        ) == BiometricManager.BIOMETRIC_SUCCESS
    }
    
    private fun showBiometricPrompt() {
        if (btnBiometric.isEnabled) {
            biometricPrompt.authenticate(promptInfo)
        } else {
            Toast.makeText(this, "Biometric authentication not available", Toast.LENGTH_SHORT).show()
        }
    }
    
    private fun handlePasswordLogin() {
        val password = etPassword.text.toString()
        
        if (password.isEmpty()) {
            Toast.makeText(this, "Please enter password", Toast.LENGTH_SHORT).show()
            return
        }
        
        if (validatePassword(password)) {
            saveAuthenticationStatus(true)
            Toast.makeText(this, "Login successful!", Toast.LENGTH_SHORT).show()
            navigateToMainActivity()
        } else {
            Toast.makeText(this, "Invalid password", Toast.LENGTH_SHORT).show()
        }
    }
    
    private fun validatePassword(password: String): Boolean {
        return password == "password123"
    }
    
    private fun saveAuthenticationStatus(isAuthenticated: Boolean) {
        val sharedPreferences = getSharedPreferences("AuthPrefs", Context.MODE_PRIVATE)
        sharedPreferences.edit().apply {
            putBoolean("is_authenticated", isAuthenticated)
            putLong("auth_timestamp", System.currentTimeMillis())
            apply()
        }
    }
    
    private fun isUserAuthenticated(): Boolean {
        val sharedPreferences = getSharedPreferences("AuthPrefs", Context.MODE_PRIVATE)
        val isAuthenticated = sharedPreferences.getBoolean("is_authenticated", false)
        val authTimestamp = sharedPreferences.getLong("auth_timestamp", 0)
        
        val timeoutMillis = 24 * 60 * 60 * 1000L
        val currentTime = System.currentTimeMillis()
        
        if (isAuthenticated && (currentTime - authTimestamp < timeoutMillis)) {
            return true
        } else if (isAuthenticated) {
            saveAuthenticationStatus(false)
        }
        
        return false
    }
    
    private fun navigateToMainActivity() {
        val intent = Intent(this, MainActivity::class.java)
        intent.flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
        startActivity(intent)
        finish()
    }
}

class MainActivity : AppCompatActivity() {
    
    private lateinit var btnLogout: Button
    
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)
        
        btnLogout = findViewById(R.id.btnLogout)
        
        btnLogout.setOnClickListener {
            logout()
        }
    }
    
    private fun logout() {
        val sharedPreferences = getSharedPreferences("AuthPrefs", Context.MODE_PRIVATE)
        sharedPreferences.edit().apply {
            putBoolean("is_authenticated", false)
            remove("auth_timestamp")
            apply()
        }
        
        val intent = Intent(this, LoginActivity::class.java)
        intent.flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
        startActivity(intent)
        finish()
    }
}